import argparse
import guava
import uvicorn
import secrets
import os

from urllib.parse import urljoin
from guava.examples.thai_palace import ThaiPalaceCallController
from fastapi import FastAPI
from guava.helpers.fastapi import create_router
from guava import logging_utils

app = FastAPI()

if __name__ == "__main__":
    logging_utils.configure_logging()
    
    parser = argparse.ArgumentParser(description="Run the Thai Palace FastAPI server")
    parser.add_argument("--host", default="127.0.0.1", help="Host to bind to")
    parser.add_argument("--port", type=int, default=8000, help="Port to listen on")
    parser.add_argument("--public-url", type=str, required=True, help="Public URL that this site is reachable at.")
    args = parser.parse_args()

    # Generate a secret token that we will pass to the Guava server. When the server
    # initiates a connection with our handler, it will pass back the provided secret token,
    # so we can validate the request actually came from Guava.    
    inbound_token = secrets.token_urlsafe(40)
    app.include_router(create_router(path="/inbound-call", controller_class=ThaiPalaceCallController, inbound_token=inbound_token))

    client = guava.Client()
    client.set_inbound_handler(os.environ['GUAVA_AGENT_NUMBER'], urljoin(args.public_url, "/inbound-call"), inbound_token)
    
    uvicorn.run(
        app,
        host=args.host,
        port=args.port,
        log_config=None,
    )